import { useEffect, useState } from "react";
import api from "../api";

const money = n => (Number(n||0)).toLocaleString("vi-VN") + " ₫";

export default function Dashboard() {
    const [metrics, setMetrics] = useState({ customers: 0, contracts: 0, paid: 0, due: 0 });
    const [recentContracts, setRecentContracts] = useState([]);
    const [events, setEvents] = useState([]);

    useEffect(() => {
        (async () => {
            try {
                const [cus, cts, pays, evs] = await Promise.all([
                    api.get("/api/customers"),
                    api.get("/api/contracts"),
                    api.get("/api/payments"),
                    api.get("/api/events"),
                ]);
                const customers = cus.data || [];
                const contracts = cts.data || [];
                const payments = pays.data || [];
                const paid = payments
                    .filter(p => p.status === "PAID" || p.status === "Đã thanh toán")
                    .reduce((s, p) => s + Number(p.amount || 0), 0);
                const total = contracts.reduce((s, c) => s + Number(c.totalAmount || c.value || 0), 0);
                setMetrics({
                    customers: customers.length,
                    contracts: contracts.length,
                    paid,
                    due: Math.max(total - paid, 0),
                });
                setRecentContracts(
                    [...contracts]
                        .sort((a,b) => (new Date(b.createdAt||b.signedDate||0)) - (new Date(a.createdAt||a.signedDate||0)))
                        .slice(0,4)
                );
                setEvents(
                    [...(evs.data || [])]
                        .sort((a,b) => (a.date||a.eventDate||"").localeCompare(b.date||b.eventDate||""))
                        .slice(0,5)
                );
            } catch (e) {
                console.error(e);
            }
        })();
    }, []);

    return (
        <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-4">
                <Card title="Khách hàng" value={metrics.customers} color="indigo" />
                <Card title="Hợp đồng" value={metrics.contracts} color="emerald" />
                <Card title="Đã thu" value={money(metrics.paid)} color="amber" />
                <Card title="Còn lại" value={money(metrics.due)} color="rose" />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <div className="lg:col-span-2 p-5 rounded-2xl bg-white shadow border border-indigo-100">
                    <div className="flex items-center justify-between mb-4">
                        <div className="font-semibold">Hợp đồng gần đây</div>
                    </div>
                    <div className="space-y-3">
                        {recentContracts.map(c => (
                            <div key={c.id} className="p-4 rounded-xl border border-indigo-100 hover:bg-indigo-50/40 flex items-center justify-between">
                                <div>
                                    <div className="font-semibold">{c.code || c.contractCode || `#${c.id}`}</div>
                                    <div className="text-sm text-slate-500">{c.type || c.contractType}</div>
                                    <div className="text-xs text-slate-500 mt-1">
                                        Trạng thái: <span className="px-2 py-0.5 bg-slate-100 rounded-full">{c.status}</span>
                                    </div>
                                </div>
                                <div className="text-right">
                                    <div className="text-sm text-slate-500">Giá trị</div>
                                    <div className="font-semibold">{money(c.totalAmount || c.value)}</div>
                                </div>
                            </div>
                        ))}
                        {recentContracts.length === 0 && <div className="text-sm text-slate-500">Chưa có dữ liệu</div>}
                    </div>
                </div>
                <div className="p-5 rounded-2xl bg-white shadow border border-indigo-100">
                    <div className="flex items-center justify-between mb-4">
                        <div className="font-semibold">Sự kiện sắp tới</div>
                    </div>
                    <div className="space-y-3">
                        {events.map(e => (
                            <div key={e.id} className="p-3 rounded-xl border border-indigo-100 hover:bg-indigo-50/40">
                                <div className="flex items-center justify-between">
                                    <div className="font-medium">{e.type || e.eventType}</div>
                                    <div className="text-xs text-slate-500">{e.date || e.eventDate}{e.time? ` • ${e.time}`:""}</div>
                                </div>
                                <div className="text-xs text-slate-500 mt-1">{e.note || ""}</div>
                            </div>
                        ))}
                        {events.length === 0 && <div className="text-sm text-slate-500">Chưa có dữ liệu</div>}
                    </div>
                </div>
            </div>
        </div>
    );
}

function Card({ title, value, color }) {
    const colorMap = {
        indigo: "bg-indigo-600",
        emerald: "bg-emerald-600",
        amber: "bg-amber-600",
        rose: "bg-rose-600"
    };
    return (
        <div className="p-5 rounded-2xl bg-white shadow border border-indigo-100">
            <div className="flex items-center justify-between">
                <div>
                    <div className="text-sm text-slate-500">{title}</div>
                    <div className="mt-1 text-2xl font-bold">{value}</div>
                </div>
                <div className={`w-10 h-10 rounded-xl grid place-content-center text-white ${colorMap[color]}`}>★</div>
            </div>
        </div>
    );
}
